import React, { useEffect, useRef } from 'react';

function DottedSphere({ size = 900, className = '' }) {
  const canvasRef = useRef(null);
  const animationRef = useRef(null);
  const timeRef = useRef(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const dpr = window.devicePixelRatio || 1;

    canvas.width = size * dpr;
    canvas.height = size * dpr;
    ctx.scale(dpr, dpr);

    const centerX = size / 2;
    const centerY = size / 2;

    // Pre-generate dots cho mỗi layer (không đổi)
    const layers = [
      { rx: size * 0.46, ry: size * 0.22, rings: 16, color: 'cyan' },
      { rx: size * 0.42, ry: size * 0.32, rings: 14, color: 'purple' },
      { rx: size * 0.38, ry: size * 0.38, rings: 12, color: 'blue' },
    ];

    const layerDots = layers.map((layer) => {
      const dots = [];
      for (let ring = 4; ring <= layer.rings; ring++) {
        const scale = ring / layer.rings;
        const rx = layer.rx * scale;
        const ry = layer.ry * scale;
        const numDots = Math.floor(24 + ring * 5);

        for (let i = 0; i < numDots; i++) {
          const angle = (i / numDots) * Math.PI * 2;
          dots.push({
            angle,
            rx,
            ry,
            ring
          });
        }
      }
      return dots;
    });

    function draw() {
      ctx.clearRect(0, 0, size, size);

      const t = timeRef.current;

      // Background glow
      const glow = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, size / 2);
      glow.addColorStop(0, 'rgba(120, 80, 255, 0.1)');
      glow.addColorStop(0.5, 'rgba(80, 200, 255, 0.05)');
      glow.addColorStop(1, 'rgba(0, 0, 0, 0)');
      ctx.fillStyle = glow;
      ctx.fillRect(0, 0, size, size);

      // Vẽ từng layer với offset dao động
      layers.forEach((layer, layerIdx) => {
        // Mỗi layer dao động với phase khác nhau
        const offsetX = Math.sin(t * 0.5 + layerIdx * 2) * 15;
        const offsetY = Math.cos(t * 0.3 + layerIdx * 1.5) * 10;
        const tilt = Math.sin(t * 0.2 + layerIdx) * 0.1;

        layerDots[layerIdx].forEach(dot => {
          let x = Math.cos(dot.angle) * dot.rx;
          let y = Math.sin(dot.angle) * dot.ry;

          // Apply tilt
          const tiltedY = y * Math.cos(tilt);
          const z = y * Math.sin(tilt);

          const finalX = centerX + x + offsetX;
          const finalY = centerY + tiltedY + offsetY - 30 + layerIdx * 40;

          // Depth-based alpha
          const depth = (z + size / 2) / size;
          const alpha = 0.25 + depth * 0.5;
          const dotSize = 1.5 + depth * 1.5;

          // Color gradient: cyan -> purple -> blue
          let color;
          if (layerIdx === 0) {
            color = `rgba(80, 220, 255, ${alpha})`; // Cyan
          } else if (layerIdx === 1) {
            color = `rgba(180, 120, 255, ${alpha})`; // Purple
          } else {
            color = `rgba(100, 140, 255, ${alpha})`; // Blue
          }

          // Glow
          ctx.beginPath();
          ctx.arc(finalX, finalY, dotSize * 3, 0, Math.PI * 2);
          ctx.fillStyle = layer.color === 'cyan' 
            ? `rgba(80, 220, 255, ${alpha * 0.1})`
            : layer.color === 'purple'
            ? `rgba(180, 120, 255, ${alpha * 0.1})`
            : `rgba(100, 140, 255, ${alpha * 0.1})`;
          ctx.fill();

          // Dot
          ctx.beginPath();
          ctx.arc(finalX, finalY, dotSize, 0, Math.PI * 2);
          ctx.fillStyle = color;
          ctx.fill();
        });
      });

      timeRef.current += 0.016;
      animationRef.current = requestAnimationFrame(draw);
    }

    draw();

    return () => {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
      }
    };
  }, [size]);

  return (
    <div className={`absolute pointer-events-none ${className}`}>
      <canvas 
        ref={canvasRef}
        style={{ width: size, height: size }}
      />
    </div>
  );
}

export default DottedSphere;
